{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl"
    ],
    "rationale": "This is a classic textbook example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (zinc chloride) and followed by hydrolysis to yield the aryl ketone product. The reactants and product are simple, acyclic where possible, and clearly illustrate the core transformation: the formation of a C(aryl)-C(=O)R bond from an arene and a nitrile.",
    "collision_avoidance_note": "This example uses a highly activated polyalkoxybenzene, which is characteristic of the Houben-Hoesch reaction and distinguishes it from the more general Friedel-Crafts acylation that typically uses acyl halides or anhydrides. The use of a simple nitrile (acetonitrile) as the acylating agent is also a key differentiator. The structure is kept simple to avoid overlap with more complex natural product syntheses or other named reactions involving arenes."
  }
}
